import ldap3
from ldap3 import Server, Connection, AUTO_BIND_NO_TLS

def search_user(username):
    server = Server('ldap.example.com', port=389)
    conn = Connection(server, user='cn=admin,dc=example,dc=com', password='password')
    
    if not conn.bind():
        print("LDAP bind failed")
        return
    
    filter = f"(uid={username})"
    escaped_filter = ldap3.utils.conv.escape_filter_chars(filter)
    
    query = "(&(objectClass=user)(%s))" % escaped_filter
    
    try:
        result = conn.search(search_base='dc=example,dc=com', search_scope=ldap3.SUBTREE,
                             search_filter=query, attributes=['*'])
        
        if result:
            for entry in conn.response:
                print(entry['attributes']['cn'][0])
        else:
            print("User not found")
    except Exception as e:
        print(f"LDAP query failed: {e}")
    
    finally:
        conn.unbind()

